/* 本地轻量 marked 兼容实现：支持表格、列表、加粗和代码块，避免演示依赖外网 CDN。 */
window.marked={parse:function(src){function esc(s){return String(s||"").replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;")}src=esc(src||"");var blocks=src.split(/\n{2,}/).map(function(block){var lines=block.split("\n");if(lines.length>1&&lines[0].includes("|")&&lines[1].includes("|")){var heads=lines[0].split("|").filter(Boolean),rows=lines.slice(2).map(function(r){return r.split("|").filter(Boolean)});return"<table><thead><tr>"+heads.map(function(h){return"<th>"+inline(h.trim())+"</th>"}).join("")+"</tr></thead><tbody>"+rows.map(function(r){return"<tr>"+r.map(function(c){return"<td>"+inline(c.trim())+"</td>"}).join("")+"</tr>"}).join("")+"</tbody></table>"}if(lines.every(function(l){return /^[-*]\s+/.test(l)})){return"<ul>"+lines.map(function(l){return"<li>"+inline(l.replace(/^[-*]\s+/,""))+"</li>"}).join("")+"</ul>"}if(/^```/.test(block)){return"<pre><code>"+block.replace(/^```[a-zA-Z]*\n?/,"").replace(/```$/,"")+"</code></pre>"}return"<p>"+inline(lines.join("<br>"))+"</p>"});function inline(s){return s.replace(/\*\*(.*?)\*\*/g,"<strong>$1</strong>").replace(/`([^`]+)`/g,"<code>$1</code>")}return blocks.join("")}};
